import type { Metadata } from "next"

import BusApproachClient from "./BusApproachClient"

export const metadata: Metadata = {
  title: "渋谷駅前 バス接近案内 | 都営バス",
  description:
    "渋谷駅前バス停の接近案内。まもなく到着・あと○分・車内混雑・遅延をリアルタイムで確認し、系統/方面で絞り込み、時刻表・運賃・IC残高・一日乗車券を表示できます。",
}

// Server Component shell. All interactive UI — function props such as
// onValueChange / onSelect / onOpenChange and the formatCurrency formatter —
// lives inside the "use client" BusApproachClient so `next build` stays green
// (the kit warns function props from an RSC break the build).
export default function BusApproachPage() {
  return (
    <main className="min-h-screen bg-background text-foreground">
      <BusApproachClient />
    </main>
  )
}

"use client"

import * as React from "react"
import {
  IconBus,
  IconWheelchair,
  IconRefresh,
  IconMapPin,
  IconChevronDown,
  IconClock,
  IconCreditCard,
  IconTicket,
} from "@tabler/icons-react"
import {
  PageHeader,
  FilterChips,
  ListCard,
  Badge,
  Button,
  Tag,
  Card,
  CardContent,
  Separator,
  LoyaltySummaryCard,
  TicketStub,
  RouteStops,
  AmountBreakdown,
  MetadataList,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  EmptyState,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  formatCurrency,
} from "@gunjo/ui"

import {
  APPROACHING,
  DIRECTIONS,
  NEARBY_STOPS,
  ROUTES,
  RIDER,
  STOP,
  type ApproachBus,
  type RouteInfo,
} from "./data"
import { CrowdingBadge } from "./CrowdingBadge"

/** あと○分 / まもなく到着 / ○つ前のバス停 を一行で表す接近表現。 */
function approachLabel(bus: ApproachBus): string {
  if (bus.minutes === null) return "接近情報なし"
  if (bus.minutes <= 0 || bus.stopsAway === 0) return "まもなく到着"
  return `あと ${bus.minutes} 分`
}

/** 系統番号チップ（路線記号）。 */
function RouteChip({ route, soon }: { route: string; soon?: boolean }) {
  return (
    <span
      className={
        "inline-flex h-11 w-11 shrink-0 items-center justify-center rounded-lg text-sm font-bold tabular-nums " +
        (soon
          ? "bg-primary text-primary-foreground"
          : "bg-secondary text-secondary-foreground")
      }
      aria-hidden="true"
    >
      {route}
    </span>
  )
}

export default function BusApproachClient() {
  const [direction, setDirection] = React.useState<string>("all")
  const [stopId, setStopId] = React.useState<string>(NEARBY_STOPS[0].id)
  const [stopSheetOpen, setStopSheetOpen] = React.useState(false)
  const [detailRoute, setDetailRoute] = React.useState<string | null>(null)
  const [scheduleDay, setScheduleDay] = React.useState<"weekday" | "holiday">("weekday")

  const activeStop = NEARBY_STOPS.find((s) => s.id === stopId) ?? NEARBY_STOPS[0]

  const buses = React.useMemo(
    () =>
      APPROACHING.filter(
        (b) => direction === "all" || b.direction === direction
      ).sort((a, b) => (a.minutes ?? 999) - (b.minutes ?? 999)),
    [direction]
  )

  // 方面フィルタに件数を載せる。
  const chips = React.useMemo(
    () =>
      DIRECTIONS.map((d) => ({
        value: d.value,
        label: d.label,
        count:
          d.value === "all"
            ? APPROACHING.length
            : APPROACHING.filter((b) => b.direction === d.value).length,
      })),
    []
  )

  const detail: RouteInfo | null = detailRoute ? ROUTES[detailRoute] ?? null : null

  return (
    <>
      <PageHeader
        title={STOP.name}
        subtitle={`${activeStop.meta} ・ 接近案内`}
        leading={<IconBus className="size-5 text-primary" aria-hidden="true" />}
        actions={
          <Button
            variant="ghost"
            size="icon"
            aria-label="最新の情報に更新"
            onClick={() => {
              /* 実機ではポーリング再取得 */
            }}
          >
            <IconRefresh className="size-5" aria-hidden="true" />
          </Button>
        }
      />

      <div className="mx-auto w-full max-w-md px-4 pb-16">
        {/* このバス停 / のりば（stop context） */}
        <section aria-label="このバス停" className="pt-3">
          <button
            type="button"
            onClick={() => setStopSheetOpen(true)}
            className="flex w-full items-center gap-2 rounded-lg border bg-card px-3 py-2.5 text-left transition-colors hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            <IconMapPin className="size-5 shrink-0 text-primary" aria-hidden="true" />
            <span className="min-w-0 flex-1">
              <span className="block truncate text-sm font-semibold text-foreground">
                {activeStop.name}
              </span>
              <span className="block truncate text-xs text-muted-foreground">
                {activeStop.meta}
              </span>
            </span>
            <span className="flex shrink-0 items-center gap-1 text-xs font-medium text-primary">
              バス停を切替
              <IconChevronDown className="size-4" aria-hidden="true" />
            </span>
          </button>
        </section>

        {/* 系統・方面の絞り込み（filter） */}
        <section aria-label="系統・方面で絞り込み" className="pt-3">
          <FilterChips
            aria-label="方面で絞り込み"
            items={chips}
            value={direction}
            onValueChange={setDirection}
          />
        </section>

        {/* 接近案内（最重要・リアルタイム） */}
        <section aria-labelledby="approach-heading" className="pt-4">
          <div className="mb-2 flex items-baseline justify-between">
            <h2 id="approach-heading" className="text-sm font-semibold text-foreground">
              まもなく来るバス
            </h2>
            <span className="text-xs text-muted-foreground" aria-live="polite">
              14:35 時点 ・ {buses.length} 件
            </span>
          </div>

          {buses.length === 0 ? (
            <EmptyState
              title="接近中のバスはありません"
              description="この方面のバスは現在接近していません。フィルタを変えるか、時刻表をご確認ください。"
            />
          ) : (
            <ul className="flex flex-col gap-2" role="list">
              {buses.map((bus, i) => {
                const soon = bus.minutes !== null && (bus.minutes <= 0 || bus.stopsAway === 0)
                return (
                  <li key={bus.id}>
                    <ListCard
                      severity={soon ? "info" : "neutral"}
                      selected={soon}
                      leading={<RouteChip route={bus.route} soon={soon} />}
                      title={
                        <span className="flex items-center gap-2">
                          <span className="truncate">{bus.destination}</span>
                          {bus.nonStep && (
                            <IconWheelchair
                              className="size-4 shrink-0 text-info"
                              aria-label="ノンステップ・車いす対応"
                            />
                          )}
                        </span>
                      }
                      description={
                        <span className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                          <span>{bus.noriba}のりば</span>
                          {bus.minutes !== null && bus.stopsAway > 0 && (
                            <span aria-hidden="true">・</span>
                          )}
                          {bus.minutes !== null && bus.stopsAway > 0 && (
                            <span>{bus.stopsAway}つ前のバス停を通過</span>
                          )}
                        </span>
                      }
                      tags={
                        <>
                          <CrowdingBadge level={bus.crowding} />
                          {bus.delayMinutes > 0 ? (
                            <Badge variant="warning" icon={<IconClock />}>
                              遅れ {bus.delayMinutes} 分
                            </Badge>
                          ) : (
                            <Badge variant="outline">定刻</Badge>
                          )}
                          {i === 0 && <Tag variant="secondary">最速</Tag>}
                        </>
                      }
                      meta={
                        <span
                          className={
                            "text-base font-bold tabular-nums " +
                            (soon ? "text-primary" : "text-foreground")
                          }
                        >
                          {approachLabel(bus)}
                        </span>
                      }
                      onSelect={() => {
                        setDetailRoute(bus.route)
                        setScheduleDay("weekday")
                      }}
                    />
                  </li>
                )
              })}
            </ul>
          )}
        </section>

        {/* 乗車 / IC（IC残高 + 一日乗車券） */}
        <section aria-label="乗車・IC" className="pt-6">
          <h2 className="mb-2 text-sm font-semibold text-foreground">乗車・IC</h2>
          <LoyaltySummaryCard
            tone="brand"
            meta={
              <span className="flex items-center gap-1.5">
                <IconCreditCard className="size-4" aria-hidden="true" />
                {RIDER.icBrand} ・ {RIDER.icNumber}
              </span>
            }
            tier={<Badge variant="outline" className="border-white/40 text-primary-foreground">IC</Badge>}
            balanceLabel="IC残高"
            balance={formatCurrency(RIDER.icBalance, { currency: "JPY" })}
            secondary={[{ label: "有効な乗車券", value: RIDER.passName }]}
            alert={RIDER.passValidUntil}
            action={
              <Button
                variant="secondary"
                size="sm"
                onClick={() => setDetailRoute("__ticket__")}
              >
                <IconTicket className="size-4" aria-hidden="true" />
                一日乗車券を表示
              </Button>
            }
          />
        </section>
      </div>

      {/* バス停切替シート */}
      <Sheet open={stopSheetOpen} onOpenChange={setStopSheetOpen}>
        <SheetContent side="bottom" className="max-h-[80vh]">
          <SheetHeader>
            <SheetTitle>近くのバス停</SheetTitle>
            <SheetDescription>
              接近案内を表示するバス停・のりばを選んでください。
            </SheetDescription>
          </SheetHeader>
          <ul className="mt-3 flex flex-col gap-2" role="list">
            {NEARBY_STOPS.map((s) => (
              <li key={s.id}>
                <ListCard
                  leading={<IconMapPin className="size-5 text-muted-foreground" aria-hidden="true" />}
                  title={s.name}
                  description={s.meta}
                  selected={s.id === stopId}
                  status={
                    s.id === stopId ? <Badge variant="info">表示中</Badge> : undefined
                  }
                  onSelect={() => {
                    setStopId(s.id)
                    setStopSheetOpen(false)
                  }}
                />
              </li>
            ))}
          </ul>
        </SheetContent>
      </Sheet>

      {/* 系統の詳細：時刻表 + 運賃 + 経路 / または 一日乗車券 */}
      <Sheet
        open={detailRoute !== null}
        onOpenChange={(o) => !o && setDetailRoute(null)}
      >
        <SheetContent side="bottom" className="max-h-[88vh] overflow-y-auto">
          {detailRoute === "__ticket__" ? (
            <>
              <SheetHeader>
                <SheetTitle>{RIDER.passName}</SheetTitle>
                <SheetDescription>{RIDER.passValidUntil}</SheetDescription>
              </SheetHeader>
              <div className="mt-4">
                <TicketStub
                  value={RIDER.passCode}
                  format="qr"
                  codeLabel={RIDER.passCode}
                  codeAlt="一日乗車券のQRコード"
                >
                  <div className="space-y-1">
                    <p className="text-lg font-bold">{RIDER.passName}</p>
                    <p className="text-sm text-muted-foreground">
                      都営バス全線 ・ 大人
                    </p>
                    <p className="text-sm text-muted-foreground">
                      {RIDER.passValidUntil}
                    </p>
                  </div>
                </TicketStub>
                <p className="mt-3 text-center text-xs text-muted-foreground">
                  乗務員にこの画面をご提示ください。
                </p>
              </div>
            </>
          ) : detail ? (
            <RouteDetail detail={detail} day={scheduleDay} onDayChange={setScheduleDay} />
          ) : null}
        </SheetContent>
      </Sheet>
    </>
  )
}

function RouteDetail({
  detail,
  day,
  onDayChange,
}: {
  detail: RouteInfo
  day: "weekday" | "holiday"
  onDayChange: (d: "weekday" | "holiday") => void
}) {
  const times = day === "weekday" ? detail.weekday : detail.holiday

  return (
    <>
      <SheetHeader>
        <SheetTitle className="flex items-center gap-2">
          <Badge variant="info">{detail.route}</Badge>
          {detail.destination}
        </SheetTitle>
        <SheetDescription>
          {detail.interval} ・ 始発 {detail.firstBus} / 終発 {detail.lastBus}
        </SheetDescription>
      </SheetHeader>

      {/* 時刻表（timetable） */}
      <section aria-label="時刻表" className="mt-4">
        <Tabs value={day} onValueChange={(v) => onDayChange(v as "weekday" | "holiday")}>
          <TabsList className="w-full">
            <TabsTrigger value="weekday" className="flex-1">
              平日
            </TabsTrigger>
            <TabsTrigger value="holiday" className="flex-1">
              土休日
            </TabsTrigger>
          </TabsList>
          <TabsContent value={day} className="px-0 pb-0">
            <p className="mb-2 text-xs text-muted-foreground">この先の発車時刻</p>
            <ul className="flex flex-wrap gap-2" role="list">
              {times.map((t, i) => (
                <li key={t}>
                  <span
                    className={
                      "inline-flex h-9 items-center rounded-lg border px-3 text-sm font-semibold tabular-nums " +
                      (i === 0
                        ? "border-primary bg-primary/10 text-primary"
                        : "border-border bg-card text-foreground")
                    }
                  >
                    {t}
                    {i === 0 && <span className="ml-1.5 text-xs font-normal">次発</span>}
                  </span>
                </li>
              ))}
            </ul>
          </TabsContent>
        </Tabs>
      </section>

      <Separator className="my-4" />

      {/* 運賃（fare） */}
      <section aria-label="運賃">
        <div className="mb-2 flex items-center gap-2">
          <h3 className="text-sm font-semibold text-foreground">運賃</h3>
          <Badge variant="secondary">
            {detail.fareType === "flat" ? "均一運賃" : "区間運賃"}
          </Badge>
        </div>
        <AmountBreakdown
          lines={[
            { label: "大人（IC）", amount: detail.adultIc },
            { label: "大人（現金）", amount: detail.adultCash },
            { label: "小児（IC）", amount: detail.childIc },
          ]}
          total={{ label: "大人IC運賃", amount: detail.adultIc }}
          formula={
            detail.fareType === "flat"
              ? "全区間同一運賃（均一）"
              : "乗車区間により変動（区間運賃）"
          }
        />
        <MetadataList
          className="mt-2"
          variant="compact"
          items={[
            { label: "お支払い", value: "PASMO / Suica / 現金" },
            {
              label: "IC / 現金 差額",
              value:
                detail.adultIc === detail.adultCash
                  ? "なし"
                  : `${formatCurrency(detail.adultCash - detail.adultIc, { currency: "JPY" })} お得（IC）`,
            },
          ]}
        />
      </section>

      <Separator className="my-4" />

      {/* 経路（各停留所の通過） */}
      <section aria-label="経路">
        <h3 className="mb-2 text-sm font-semibold text-foreground">経路・主な停留所</h3>
        <RouteStops
          hideTimes
          statusLabels={{ current: "乗車", pending: "通過予定", completed: "通過済" }}
          stops={detail.via.map((name, i) => ({
            id: `${detail.route}-${i}`,
            title: name,
            status: i === 0 ? "current" : "pending",
          }))}
        />
      </section>

      <Card className="mt-4 bg-muted/40">
        <CardContent className="py-3 text-xs text-muted-foreground">
          時刻・接近情報はリアルタイムの運行状況により変動します。遅延時は表示が前後する場合があります。
        </CardContent>
      </Card>
    </>
  )
}

import * as React from "react"
import { IconUser, IconUsers, IconUsersGroup } from "@tabler/icons-react"
import { Badge } from "@gunjo/ui"

import { CROWDING_LABEL, type Crowding } from "./data"

// HAND-ROLLED — gap: @gunjo/ui has no qualitative-status / "level" component
// (空いています / やや混雑 / 混雑). /docs/by-use-case routed "crowding" to
// HeatmapChart, which is a read-only intensity *grid* — wrong for a single
// per-bus three-level status pill. Badge IS the right primitive though: it
// takes a tone `variant` + a leading `icon`, so the level never rides on
// colour alone. This wrapper is just the bus-domain mapping on top of Badge.
const CONFIG: Record<
  Crowding,
  { variant: "success" | "warning" | "destructive"; icon: React.ReactNode }
> = {
  empty: { variant: "success", icon: <IconUser /> },
  some: { variant: "warning", icon: <IconUsers /> },
  crowded: { variant: "destructive", icon: <IconUsersGroup /> },
}

export function CrowdingBadge({ level }: { level: Crowding }) {
  const { variant, icon } = CONFIG[level]
  return (
    <Badge variant={variant} icon={icon}>
      {CROWDING_LABEL[level]}
    </Badge>
  )
}
